21	
22	  const maxCols = Math.max(...grid.map(row => row.length));
23	
24	  return grid.map((_, r) => {
25	    const newRow: boolean[] = [];
26	    for (let c = -1; c <= maxCols; c++) {
27	      const alive = getCell(grid, r, c);
28	      const neighbors = countNeighbors(grid, r, c);
29	      if (alive ? neighbors === 2 || neighbors === 3 : neighbors === 3) {
30	        newRow.push(true);
31	      }
